claimStake: () => {
  const { activeStake, floor, seed } = get()
  if (!activeStake || get().stakeClaimed) return
  set({ stakeClaimed: true })
  const rng = makeRng(seed ^ 0xd4e5f612 ^ (floor * 0x9e3779b9))
  if (rng() < 0.35) {
    const item = rollLoot(rng, 'chest', floor, 50)
    if (item) { set({ stakeBonusItem: item }); return }
  }
  scheduleSave()
}
